/** Tokenizer for JSON structures using circe. */
class JsonTokenizer(pretty: Boolean = false) {

  def tokenize(value: Json): Token = {
    val jsonStr = if (pretty) value.spaces2 else value.noSpaces
    Token(jsonStr, TokenType.STRUCTURED, Map(\"json\" -> true))
  }

  /** Extract and tokenize a value at a dot-separated JSON path. */
  def tokenizePath(value: Json, path: String): Option[Token] = {
    val parts = path.split(\"\\\\\\\\.\").toList
    traversePath(value, parts).map(tokenize)
  }

  private def traversePath(json: Json, parts: List[String]): Option[Json] = parts match {
    case Nil => Some(json)
    case head :: tail =>
      val next = json.asObject.flatMap(_(head))
        .orElse {
          for {
            arr <- json.asArray
            idx <- Try(head.toInt).toOption
            elem <- arr.lift(idx)
          } yield elem
        }
      next.flatMap(traversePath(_, tail))
  }
}\"\"\")

