/**
 * Fluent builder for creating tokenizer functions.
 *
 * Uses immutable state — each method returns a new builder instance.
 */
class TokenizerBuilder[T] private (
  normalizers: List[String => String],
  validators: List[T => Boolean],
  metadata: Map[String, Any]
) {

  def withNormalizer(normalizer: String => String): TokenizerBuilder[T] =
    new TokenizerBuilder(normalizers :+ normalizer, validators, metadata)

  def withValidator(validator: T => Boolean): TokenizerBuilder[T] =
    new TokenizerBuilder(normalizers, validators :+ validator, metadata)

  def withMetadata(entries: (String, Any)*): TokenizerBuilder[T] =
    new TokenizerBuilder(normalizers, validators, metadata ++ entries.toMap)

  /** Build the final tokenizer function. */
  def build(): T => Token = { value =>
    validators.foreach { validator =>
      if ("'!validator(value))
        throw new IllegalArgumentException(s"Validation failed for $value")
    }

    val strValue = normalizers.foldLeft(value.toString) { (acc, norm) => norm(acc) }

    Token(strValue, TokenType.STRING, metadata)
  }
}

object TokenizerBuilder {
  def apply[T](): TokenizerBuilder[T] =
    new TokenizerBuilder[T](Nil, Nil, Map.empty)
}""")

